UPDATE Inventory


    CurrentQty = #{currentQty}




    PurchaseQty = #{purchaseQty}




    PurchaseReturnQty = #{purchaseReturnQty}




    SaleQty = #{saleQty}




    SaleReturnQty = #{saleReturnQty}



  Id = #{id}

mapper.select:
SELECT I.*, S.Name AS StoreName, P.Name AS ProductName
FROM Inventory AS I
INNER JOIN Store AS S ON I.StoreId = S.Id
INNER JOIN ProductSku AS PS ON I.ProductSkuId = PS.Id
INNER JOIN Product AS P ON PS.ProductId = P.Id


    AND I.Id = #{id}


    AND I.StoreId IN

      #{id}



    AND I.ProductSkuId IN

      #{id}



    AND I.CurrentQty >= #{currentQtyS}


    AND I.CurrentQty <= #{currentQtyE}


    AND I.PurchaseQty >= #{purchaseQtyS}


    AND I.PurchaseQty <= #{purchaseQtyE}


    AND I.PurchaseReturnQty >= #{purchaseReturnQtyS}


    AND I.PurchaseReturnQty <= #{purchaseReturnQtyE}


    AND I.SaleQty >= #{saleQtyS}


    AND I.SaleQty <= #{saleQtyE}


    AND I.SaleReturnQty >= #{saleReturnQtyS}


    AND I.SaleReturnQty <= #{saleReturnQtyE}


    AND I.ActualQty >= #{actualQtyS}


    AND I.ActualQty <= #{actualQtyE}


ORDER BY Id
